# Sessions: token -> { username, role, nombre, expires }
# También soporta tokens firmados HMAC para persistencia entre reinicios
SESSIONS = {}
SESSION_SECRET = os.environ.get("SESSION_SECRET", "ica2025secretkey_almacen_produkt")

STATIC_ADMIN_TOKEN = "ica2025admin-script"  # For Apps Script automation

def get_session(request):
    token = request.headers.get('X-Session-Token') or request.cookies.get('session_token')
    if not token:
        return None
    # Static token for Apps Script / automation
    if token == STATIC_ADMIN_TOKEN or token == "ica2025admin":
        return {"username": "script", "role": "admin", "nombre": "Apps Script"}
    # Verificar en memoria primero
    session = SESSIONS.get(token)
    if session:
        if datetime.now() > session['expires']:
            del SESSIONS[token]
        else:
            return session
    # Intentar validar token firmado HMAC (persiste entre reinicios de Railway)
    try:
        import hmac as _hmac, time as _time
        parts = token.rsplit(':', 1)
        if len(parts) == 2:
            payload, sig_recv = parts
            sig_calc = _hmac.new(SESSION_SECRET.encode(), payload.encode(), 'sha256').hexdigest()[:16]
            if _hmac.compare_digest(sig_calc, sig_recv):
                p_parts = payload.split(':')
                if len(p_parts) == 3:
                    username, role, expires_ts = p_parts
                    if int(_time.time()) < int(expires_ts):
                        # Buscar nombre del usuario
                        user_data = USUARIOS.get(username, {})
                        session = {"username": username, "role": role, "nombre": user_data.get("nombre", username)}
                        SESSIONS[token] = {**session, "expires": datetime.now() + timedelta(hours=24)}
                        return session
    except:
        pass
    return None

def require_auth(roles=None):
    def decorator(f):
        from functools import wraps
        @wraps(f)
        def wrapped(*args, **kwargs):
            session = get_session(request)
            if not session:
                return jsonify({"error": "No autorizado", "auth_required": True}), 401
            if roles and session['role'] not in roles:
                return jsonify({"error": "Sin permisos"}), 403
            return f(*args, **kwargs)
        return wrapped
    return decorator

@app.route("/api/login", methods=["POST"])
def login():
    data = request.get_json()
    username = str(data.get("usuario", data.get("username", ""))).strip().lower()
    password = str(data.get("password", ""))
    
    user = USUARIOS.get(username)
    if not user:
        return jsonify({"ok": False, "error": "Usuario o contraseña incorrectos"})
    
    password_hash = hashlib.sha256(password.encode()).hexdigest()
    if password_hash != user["hash"]:
        return jsonify({"ok": False, "error": "Usuario o contraseña incorrectos"})
    
    # Token firmado HMAC - persiste aunque Railway reinicie
    import hmac as _hmac, time as _time
    expires_ts = int(_time.time()) + 86400 * 7  # 7 días
    payload = f"{username}:{user['role']}:{expires_ts}"
    sig = _hmac.new(SESSION_SECRET.encode(), payload.encode(), 'sha256').hexdigest()[:16]
    token = f"{payload}:{sig}"
    SESSIONS[token] = {
        "username": username,
        "role": user["role"],
        "nombre": user["nombre"],
        "expires": datetime.now() + timedelta(days=7)
    }
    
    return jsonify({
        "ok": True,
        "token": token,
        "usuario": {
            "usuario": username,
            "nombre": user["nombre"],
            "role": user["role"]
        }
    })

@app.route("/api/logout", methods=["POST"])
def logout():
    token = request.headers.get('X-Session-Token')
    if token and token in SESSIONS:
        del SESSIONS[token]
    return jsonify({"ok": True})

