def get_sheets_service():
    creds = service_account.Credentials.from_service_account_info(
        SERVICE_ACCOUNT_INFO, scopes=SCOPES
    )
    return build("sheets", "v4", credentials=creds)

def sheet_to_dataframe(service, sheet_name):
    result = service.spreadsheets().values().get(
        spreadsheetId=SHEET_ID,
        range=sheet_name
    ).execute()
    values = result.get("values", [])
    if not values or len(values) < 2:
        return pd.DataFrame()
    headers = values[0]
    rows = values[1:]
    # Normalizar longitud de filas
    rows_norm = []
    for r in rows:
        if len(r) < len(headers):
            r = r + [""] * (len(headers) - len(r))
        else:
            r = r[:len(headers)]
        rows_norm.append(r)
    return pd.DataFrame(rows_norm, columns=headers)

def normalizar_fecha(f):
    val = str(f).strip()
    if not val or val in ('', 'None', 'nan'):
        return ''
    # Número Excel (serial date)
    if val.isdigit() and len(val) == 5:
        try:
            fecha = datetime(1899, 12, 30) + timedelta(days=int(val))
            return fecha.strftime("%d/%m/%Y")
        except:
            pass
    # DD/MM/YYYY o D/M/YYYY
    try:
        partes = val.split("/")
        if len(partes) == 3:
            d = partes[0].zfill(2)
            mo = partes[1].zfill(2)
            y = partes[2].strip()
            if len(y) == 2: y = '20' + y
            return f"{d}/{mo}/{y}"
    except:
        pass
    # YYYY-MM-DD (ISO)
    try:
        partes = val.split("-")
        if len(partes) == 3 and len(partes[0]) == 4:
            return f"{partes[2].zfill(2)}/{partes[1].zfill(2)}/{partes[0]}"
    except:
        pass
    # DD-MM-YYYY
    try:
        partes = val.split("-")
        if len(partes) == 3 and len(partes[2]) == 4:
            return f"{partes[0].zfill(2)}/{partes[1].zfill(2)}/{partes[2]}"
    except:
        pass
    # Fecha con hora: "27/02/2026 0:39" → solo la fecha
    try:
        if ' ' in val:
            return normalizar_fecha(val.split(' ')[0])
    except:
        pass
    return val



