@app.route("/api/chat", methods=["POST"])
def chat():
    data = request.json
    pregunta = data.get("pregunta", "").strip()
    historial = data.get("historial", [])

    if not pregunta:
        return jsonify({"error": "Pregunta vacia"}), 400

    df_pedidos, df_cargas, error = load_data()
    if error:
        return jsonify({"respuesta": f"No puedo cargar los datos: {error}"})

    contexto = dataframes_to_context(df_pedidos, df_cargas)

    system_prompt = f"""Eres el asistente de almacen de ICA PRODUKT. Tienes acceso a los pedidos y cargas.
Responde en espanol, de forma clara y directa, como si hablaras con el jefe de almacen.
Para pedidos concretos muestra toda la info: producto, bultos, palets, transportista, matricula, observaciones.
Si hay campos vacios que deberian tener valor (matricula, transportista) indicalos como pendientes.
Si no encuentras un pedido dilo claramente.

DATOS:
{contexto}
"""

    messages = []
    for h in historial[-6:]:
        role = "user" if h["role"] == "user" else "assistant"
        messages.append({"role": role, "content": h["content"]})
    messages.append({"role": "user", "content": pregunta})

    try:
        response = client.messages.create(
            model="claude-haiku-4-5-20251001",
            max_tokens=800,
            system=system_prompt,
            messages=messages
        )
        return jsonify({"respuesta": response.content[0].text})
    except anthropic.RateLimitError:
        return jsonify({"respuesta": "Demasiadas peticiones. Espera unos segundos e intentalo de nuevo."})
    except Exception as e:
        return jsonify({"respuesta": f"Error: {str(e)}"})

@app.route("/api/estandares")
def get_estandares():
    """Lee hoja Estandares del sheet para planificación inteligente"""
    try:
        service = get_sheets_service()
        result = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID,
            range="Estandares!A:K"
        ).execute()
        rows = result.get("values", [])
        if not rows:
            return jsonify({"ok": False, "error": "Hoja Estandares vacía o no existe"})
        
        headers = rows[0]
        estandares = []
        for row in rows[1:]:
            if not row: continue
            d = {}
            for i, h in enumerate(headers):
                d[h] = row[i] if i < len(row) else ""
            if d.get("PRODUCTO"):
                # Convert numeric fields
                for campo in ["MEDIA_MIN_PALET","MIN_PALET_MIN","MIN_PALET_MAX","BULTOS_PALET","PESO_CAJA","UDS_PALET","PERSONAS_HABITUAL","N_REGISTROS"]:
                    try: d[campo] = float(d[campo]) if d.get(campo) else None
                    except: d[campo] = None
                estandares.append(d)
        
        return jsonify({"ok": True, "estandares": estandares, "total": len(estandares)})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})

@app.route("/api/planificacion")
def planificacion():
    df_pedidos, _, error = load_data()
    if error:
        return jsonify({"error": error})
    if df_pedidos.empty:
        return jsonify({"dias": {}})

    # Buscar columna fecha salida
    fecha_col = None
    for col in df_pedidos.columns:
        if "salida" in col.lower():
            fecha_col = col
            break
    if not fecha_col:
        # Mostrar columnas disponibles para debug
        return jsonify({"error": "No columna Fecha Salida. Columnas: " + str(list(df_pedidos.columns))})

    # DEBUG: ver muestra de fechas
    sample_fechas = df_pedidos[fecha_col].tail(10).astype(str).tolist()

    # Agrupar por fecha de salida
    dias = {}
    for _, row in df_pedidos.iterrows():
        fecha = normalizar_fecha(row.get(fecha_col, ""))
        if not fecha or fecha == "None" or fecha == "":
            continue
        if fecha not in dias:
            dias[fecha] = []
        pedido_num = str(row.get("Pedido", ""))
        def _s(col_name):
            for col in row.index if hasattr(row,'index') else []:
                if col_name.lower() in str(col).lower():
                    v = row[col]
                    return str(v) if v and str(v) != "nan" else ""
            return str(row.get(col_name, "") or "")
        entry = {
            "pedido":        pedido_num,
            "cliente":       str(row.get("Cliente", "") or ""),
            "producto":      str(row.get("Producto", "") or ""),
            "bultos":        str(row.get("Bultos", "") or ""),
            "palets":        str(row.get("Palets", "") or ""),
            "transportista": str(row.get("Transportista", "") or ""),
            "matricula":     str(row.get("Matricula", "") or ""),
            "lote":          str(row.get("Lote", "") or ""),
            "envase":        str(row.get("Envase", "") or ""),
            "tipo":          str(row.get("Tipo", "") or ""),
            "destino":       str(row.get("Destino", "") or ""),
            "referencia":    str(row.get("Referencia", "") or ""),
            "tipo_palet":    str(row.get("Tipo Palet", "") or ""),
            "kilos":         str(row.get("Kilos", "") or ""),
            "fecha_pedido":  str(row.get("Fecha Pedido", "") or ""),
            "fecha_llegada": str(row.get("Fecha Llegada", "") or ""),
            "modificacion":  False
        }
        # Detectar modificacion: mismo pedido+producto ya existe en este dia
        if fecha in dias:
            for prev in dias[fecha]:
                if prev["pedido"] == pedido_num and prev["producto"] == entry["producto"]:
                    prev["modificacion"] = True
                    entry["modificacion"] = True
                    break
        dias[fecha].append(entry)

    return jsonify({"dias": dias, "debug_fechas": sample_fechas})




@app.route("/api/cargas/registrar", methods=["POST"])
def registrar_carga():
    """Escribe matrícula, cargado_por y hora_carga en la fila del pedido en hoja Cargas,
       y también graba el estado en hoja Estado."""
    try:
        import json as json_mod
        data = request.get_json()
        pedido     = str(data.get("pedido", "")).strip()
        matricula  = str(data.get("matricula", "")).strip().upper()
        cargado_por= str(data.get("cargado_por", "")).strip()
        observaciones = str(data.get("observaciones", "")).strip()
        hora       = now_madrid().strftime("%H:%M")
        fecha      = now_madrid().strftime("%d/%m/%Y")

        if not pedido:
            return jsonify({"ok": False, "error": "Pedido requerido"})

        service = get_sheets_service()

        # --- 1. Actualizar fila en hoja Cargas ---
        result = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID,
            range="Cargas!A:Z"
        ).execute()
        rows = result.get("values", [])

        if rows:
            headers = rows[0]
            # Find column indices
            def find_col(keywords):
                for kw in keywords:
                    for i, h in enumerate(headers):
                        if kw.lower() in str(h).lower():
                            return i
                return -1

            col_pedido   = find_col(["pedido"])
            col_mat      = find_col(["matricul", "matrícul"])
            col_estado   = find_col(["estado"])
            col_carg_por = find_col(["cargado por", "cargado_por", "operario", "quien"])
            col_hora     = find_col(["hora carga", "hora_carga", "hora"])
            col_obs      = find_col(["observ"])

            updates = []
            def col_letter(n):
                # Convert 0-indexed col number to A, B, ... Z, AA...
                result = ""
                n += 1
                while n:
                    n, r = divmod(n-1, 26)
                    result = chr(65+r) + result
                return result

            for row_idx, row in enumerate(rows[1:], 2):  # row_idx is sheet row (1-based, skip header)
                if col_pedido >= 0 and col_pedido < len(row):
                    if str(row[col_pedido]).strip() == pedido:
                        # Update this row
                        if col_mat >= 0 and matricula:
                            updates.append({"range": f"Cargas!{col_letter(col_mat)}{row_idx}", "values": [[matricula]]})
                        if col_estado >= 0:
                            updates.append({"range": f"Cargas!{col_letter(col_estado)}{row_idx}", "values": [["cargado"]]})
                        if col_carg_por >= 0 and cargado_por:
                            updates.append({"range": f"Cargas!{col_letter(col_carg_por)}{row_idx}", "values": [[cargado_por]]})
                        if col_hora >= 0:
                            updates.append({"range": f"Cargas!{col_letter(col_hora)}{row_idx}", "values": [[hora]]})
                        if col_obs >= 0 and observaciones:
                            updates.append({"range": f"Cargas!{col_letter(col_obs)}{row_idx}", "values": [[observaciones]]})
                        # If no matching columns, at least append a note at the end of the row
                        if not updates:
                            last_col = len(headers)
                            updates.append({"range": f"Cargas!{col_letter(last_col)}{row_idx}", "values": [[f"Cargado {hora} por {cargado_por} · {matricula}"]]})
                        break  # Only update first matching row

            if updates:
                service.spreadsheets().values().batchUpdate(
                    spreadsheetId=SHEET_ID,
                    body={"valueInputOption": "RAW", "data": updates}
                ).execute()

        # --- 2. También guardar en hoja Estado para que /api/cargas lo lea ---
        ensure_estado_sheet(service)
        ts = now_madrid().strftime("%Y-%m-%d %H:%M:%S")
        valor = json_mod.dumps({
            "estado": "cargado",
            "matricula": matricula,
            "cargado_por": cargado_por,
            "hora_carga": hora,
            "observaciones": observaciones
        }, ensure_ascii=False)
        service.spreadsheets().values().append(
            spreadsheetId=SHEET_ID,
            range=f"{ESTADO_SHEET}!A1",
            valueInputOption="RAW",
            insertDataOption="INSERT_ROWS",
            body={"values": [[ts, pedido, "estado_pedido", valor]]}
        ).execute()

        return jsonify({"ok": True, "hora": hora})

    except Exception as e:
        import traceback
        return jsonify({"ok": False, "error": str(e), "trace": traceback.format_exc()})

@app.route("/api/estado", methods=["GET"])
def get_estado():
    """Return all estado entries from last 24h"""
    try:
        service = get_sheets_service()
        ensure_estado_sheet(service)
        result = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID,
            range=f"{ESTADO_SHEET}!A:D"
        ).execute()
        rows = result.get("values", [])
        if len(rows) <= 1:
            return jsonify({"ok": True, "estados": [], "palets": []})

        cutoff = now_madrid() - timedelta(hours=24)
        estados = []
        palets = []

        import json as json_mod
        for row in rows[1:]:
            if len(row) < 4:
                continue
            try:
                ts = datetime.strptime(row[0], "%Y-%m-%d %H:%M:%S")
            except:
                continue
            if ts < cutoff:
                continue
            tipo = row[2]
            valor = row[3]
            if tipo == "estado_pedido":
                entry = {"pedido": row[1], "estado": valor, "tipo": tipo}
                # Try to parse JSON valor for extra fields
                try:
                    v = json_mod.loads(valor)
                    if isinstance(v, dict):
                        entry["estado"] = v.get("estado", valor)
                        entry["matricula"] = v.get("matricula", "")
                        entry["cargado_por"] = v.get("cargado_por", "")
                        entry["hora_carga"] = v.get("hora_carga", "")
                        entry["observaciones"] = v.get("observaciones", "")
                except:
                    pass
                estados.append(entry)
            elif tipo in ("palet_man_fin", "traza_palet"):
                estados.append({"pedido": row[1], "estado": tipo, "valor": valor, "tipo": tipo})
            elif tipo == "palet_activo":
                try:
                    palets.append(json_mod.loads(valor))
                except:
                    pass
            elif tipo == "palet_finalizado":
                palets = [p for p in palets if not (str(p.get("pedido")) == row[1] and str(p.get("key","")) == valor)]

        return jsonify({"ok": True, "estados": estados, "palets": palets})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e), "estados": [], "palets": []})

