@app.route("/api/importar-pdf", methods=["POST"])
def importar_programa():
    """Parse PDF de Netagro sin IA - parser directo por regex"""
    import io as _io, re as _re
    try:
        if 'pdf' not in request.files:
            return jsonify({"ok": False, "error": "No se recibio PDF"})

        file = request.files['pdf']
        file_bytes = file.read()

        with pdfplumber.open(_io.BytesIO(file_bytes)) as _pdf:
            pages_text = []
            for p in _pdf.pages:
                t = p.extract_text()
                if t: pages_text.append(t)
        full_text = "\n".join(pages_text)

        if not full_text.strip():
            return jsonify({"ok": False, "error": "No se pudo extraer texto del PDF"})

        # Limpiar caracteres duplicados o triplicados (bug de pdfplumber en ciertos PDFs)
        def _fix_duplicados(texto):
            import re as _rx

            def _fix_n(linea, n):
                """Toma 1 de cada n caracteres no-espacio"""
                r = []; i = 0
                while i < len(linea):
                    r.append(linea[i])
                    i += (n if linea[i] not in ' \t' else 1)
                return ''.join(r)

            def _fix_linea(linea):
                if len(linea) < 6: return linea
                letras = [c for c in linea if c.isalpha()]
                if len(letras) >= 6:
                    # Detectar triplicados: AAA→A
                    triples = sum(1 for i in range(0, len(letras)-2, 3)
                                 if letras[i]==letras[i+1]==letras[i+2])
                    if triples / max(1, len(letras)//3) > 0.8:
                        return _fix_n(linea, 3)
                    # Detectar duplicados: AA→A
                    duples = sum(1 for i in range(0, len(letras)-1, 2)
                                if letras[i]==letras[i+1])
                    if duples / max(1, len(letras)//2) > 0.8:
                        return _fix_n(linea, 2)
                # Arreglar solo fechas corruptas en líneas mixtas
                def _fix_fecha_m(m):
                    s = m.group(0)
                    digits = _rx.findall(r'\d', s)
                    if len(digits) >= 16:
                        clean = []; i = 0
                        while i < len(digits) and len(clean) < 8:
                            clean.append(digits[i])
                            j = i+1
                            while j < len(digits) and digits[j]==digits[i]: j+=1
                            i += (j-i) if (j-i) > 1 else 1
                        if len(clean) == 8:
                            return f"{clean[0]}{clean[1]}/{clean[2]}{clean[3]}/{clean[4]}{clean[5]}{clean[6]}{clean[7]}"
                    return s
                return _rx.sub(r'[\d/]{10,}', _fix_fecha_m, linea)

            return '\n'.join(_fix_linea(l) for l in texto.split('\n'))

        full_text = _fix_duplicados(full_text)

        def parsear_netagro(texto):
            import re as _r
            lineas = texto.strip().split('\n')
            res = {
                'pedido': '', 'cliente': '', 'destino': '', 'referencia': '',
                'fecha_pedido': '', 'fecha_salida': '', 'fecha_llegada': '',
                'productos': []
            }

            # 1. Número de pedido
            for l in lineas:
                m = _r.search(r'Pedido[:\s]+(\d{3,5})', l)
                if m:
                    res['pedido'] = m.group(1); break
            if not res['pedido']:
                for i, l in enumerate(lineas):
                    if 'ICA PRODUKT' in l and i+1 < len(lineas):
                        cand = lineas[i+1].strip()
                        if _r.match(r'^\d{3,5}$', cand):
                            res['pedido'] = cand; break
            if not res['pedido']:
                for l in lineas:
                    ls = l.strip()
                    if _r.match(r'^\d{3,5}$', ls) and 1000 <= int(ls) <= 9999:
                        res['pedido'] = ls; break

            # 2. Fechas y cliente
            fecha_re = _r.compile(r'(\d{2}/\d{2}/\d{4})')
            for l in lineas:
                if 'Bestellnummer' in l or 'Presentaci' in l: continue
                mf = _r.search(r'Fecha:(\d{2}/\d{2}/\d{4})', l)
                if mf and not res['fecha_pedido']:
                    res['fecha_pedido'] = mf.group(1)
                fechas = fecha_re.findall(l)
                if len(fechas) >= 2 and 'Pedido:' not in l:
                    res['fecha_salida'] = fechas[1] if len(fechas) > 1 else fechas[0]
                    if len(fechas) >= 3: res['fecha_llegada'] = fechas[2]
                    sin_fechas = _r.sub(r'\d{2}/\d{2}/\d{4}', '', l).strip()
                    tokens = sin_fechas.split()
                    if tokens:
                        if _r.match(r'^\d+$', tokens[-1]):
                            res['referencia'] = tokens[-1]
                            res['cliente'] = ' '.join(tokens[:-1])
                        else:
                            res['cliente'] = ' '.join(tokens)
                    break

            # 3. Líneas de producto
            ignorar = ('CALIBRE','CONFEC','PONER','PASEO','Tlf','CIF:','PEDIDO A',
                       'REVISADO','Pedido:','Bestellnummer','ICA PRODUKT','ICA Export',
                       'Instruc','Gasto','Descuento','Totales','Total ','Obsev',
                       'CAMBIOS','ADJUNTO','ALEMANIA','AUSTRIA','ITALIA','GERMANY',
                       'Presentaci','=== ','Enviar','MERCANCIA','Las cajas','Cumple',
                       'GRASP','CMR','ATENCI','!!!','Declarar','Codigo','REMONTAMOS',
                       'CONVENCIONAL EURO','ECOLOGICO EURO','SANLUCAR','Valencia',
                       'ESPAÑA','EAN:','COMBINACI','Europastrasse','ADJUNTO CARTEL')

            CC_VALIDOS = {'I','II','III','FIANZA','PROPIO','RETORNABLE','PERDIDO','DEPOSIT'}

            TIPO_PALET_RE = _r.compile(
                r'(EURO\s*CHEP|EUROCHEP|CHEP|ECOLOGICO EURO RET|CONVENCIONAL EURO|'
                r'EURO\s*RET|IFCO|PALET GRANDE|LOSETA|PALET MEDIO|RET\.)', _r.I)

            pat_fin = _r.compile(
                r'^(.+?)\s+'
                r'(\d[\d.]*(?:,\d+)?)\s+'
                r'(\d+(?:,\d+)?)\s+'
                r'(\d+(?:,\d+)?)\s+'
                r'(\d+(?:,\d+)?)\s+'
                r'(\d+(?:,\d+)?)\s+'
                r'([A-Z])\s+(\S+)\s*$'
            )
            pat_pre = _r.compile(r'^(.+?)\s+(\d{3,6})\s+(\S+)\s+(.+)$')

            def num(s): return s.replace('.','').replace(',','.')

            for idx_l, linea in enumerate(lineas):
                ls = linea.strip()
                if not ls or len(ls) < 20: continue
                if any(ls.startswith(ig) for ig in ignorar): continue
                if _r.match(r'^[=\d]', ls): continue

                # Arreglar números pegados: "2,0080" → "2,00 80"
                ls = _r.sub(r'(\d+,\d{2})(\d+)', r'\1 \2', ls)

                mf = pat_fin.match(ls)
                if not mf: continue

                prefijo = mf.group(1).strip()
                m2 = pat_pre.match(prefijo)
                if m2:
                    nombre_raw = m2.group(1).strip()
                    lote       = m2.group(2)
                    cc_cand    = m2.group(3)
                    envase_raw = m2.group(4).strip()
                    if cc_cand.upper() in CC_VALIDOS:
                        cc     = cc_cand
                        envase = envase_raw
                    else:
                        cc     = ''
                        envase = cc_cand + ' ' + envase_raw
                    nombre = _r.sub(r'\s+(CONVENCIONAL|ECOLOGICO|ECOL)\s*$', '', nombre_raw, flags=_r.I).strip()
                else:
                    nombre = prefijo; nombre_raw = prefijo; lote = cc = envase = ''

                # Tipo palet en las 4 líneas siguientes
                tipo_palet = ''
                for jj in range(idx_l+1, min(idx_l+5, len(lineas))):
                    mtp = TIPO_PALET_RE.search(lineas[jj])
                    if mtp:
                        tipo_palet = lineas[jj].strip()
                        break

                t_cult = 'BIO' if _r.search(r'\bBio\b|\bBIO\b|\bEco\b|ECOLOGICO', nombre_raw, _r.I) else 'CONV'

                res['productos'].append({
                    'producto':   nombre,
                    't_cult':     t_cult,
                    'lote':       lote,
                    'cc':         cc,
                    'envase':     envase,
                    'tipo_palet': tipo_palet,
                    'kilos':      num(mf.group(2)),
                    'bul_plt':    num(mf.group(3)),
                    'palets':     num(mf.group(4)),
                    'bultos':     num(mf.group(5)),
                    'precio':     num(mf.group(6)),
                })
            return res

        datos = parsear_netagro(full_text)

        # Fallback: extraer pedido del nombre del archivo
        if not datos['pedido']:
            import re as _re_fn
            m_fn = _re_fn.search(r'[_-](\d{3,5})\.pdf$', file.filename or '', _re_fn.IGNORECASE)
            if m_fn: datos['pedido'] = m_fn.group(1)

        if not datos['pedido']:
            # Cartel/etiqueta sin número de pedido - ignorar silenciosamente
            return jsonify({"ok": True, "skipped": True, "motivo": "No es un pedido (sin número)", "insertadas": 0})

        if not datos['productos']:
            # PDF de pedido pero sin líneas de producto reconocibles - ignorar
            return jsonify({"ok": True, "skipped": True, "motivo": "Sin líneas de producto", "pedido": datos['pedido'], "insertadas": 0})

        # Insertar en Google Sheets
        service = get_sheets_service()
        result = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID, range="Pedidos!A:Z"
        ).execute()
        existing_rows = result.get('values', [])
        headers = existing_rows[0] if existing_rows else []

        def find_col(names):
            for n in names:
                for i, h in enumerate(headers):
                    if n.lower() in str(h).lower(): return i
            return -1

        ci = {
            'pedido':     find_col(['pedido']),
            'tipo':       find_col(['tipo']),
            'cliente':    find_col(['cliente']),
            'destino':    find_col(['destino']),
            'referencia': find_col(['referencia','ref']),
            'fecha_ped':  find_col(['fecha pedido','fecha_pedido']),
            'fecha_sal':  find_col(['fecha salida','salida']),
            'fecha_lle':  find_col(['fecha llegada','llegada']),
            'producto':   find_col(['producto','presentac']),
            't_cult':     find_col(['t.cult','tcult','t_cult']),
            'lote':       find_col(['lote']),
            'cc':         find_col(['c/c']),
            'envase':     find_col(['envase']),
            'tipo_palet': find_col(['tipo palet','tipo_palet']),
            'kilos':      find_col(['kilos']),
            'bul_plt':    find_col(['bul/plt','bul_plt']),
            'palets':     find_col(['palets']),
            'bultos':     find_col(['bultos']),
            'precio':     find_col(['precio']),
            'procesado':  find_col(['fecha procesado','procesado']),
        }

        fecha_proc = now_madrid().strftime('%d/%m/%Y %H:%M')
        n_cols = len(headers)
        insertadas = 0; omitidas = 0

        for prod in datos['productos']:
            # Verificar si ya existe este pedido+producto
            ya_existe = any(
                ci['pedido'] >= 0 and ci['pedido'] < len(row) and
                str(row[ci['pedido']]).strip() == str(datos['pedido']) and
                ci['producto'] >= 0 and ci['producto'] < len(row) and
                prod['producto'][:15].lower() in str(row[ci['producto']]).lower()
                for row in existing_rows[1:]
            )
            if ya_existe:
                omitidas += 1; continue

            nueva_fila = [''] * max(n_cols, 26)
            def set_col(key, val):
                if ci.get(key, -1) >= 0: nueva_fila[ci[key]] = val

            set_col('pedido',     datos['pedido'])
            set_col('tipo',       'PEDIDO')
            set_col('cliente',    datos['cliente'])
            set_col('destino',    datos['destino'])
            set_col('referencia', datos['referencia'])
            set_col('fecha_ped',  datos['fecha_pedido'])
            set_col('fecha_sal',  datos['fecha_salida'])
            set_col('fecha_lle',  datos['fecha_llegada'])
            set_col('producto',   prod['producto'])
            set_col('t_cult',     prod['t_cult'])
            set_col('lote',       prod.get('lote', ''))
            set_col('cc',         prod.get('cc', ''))
            set_col('envase',     prod.get('envase', ''))
            set_col('tipo_palet', prod.get('tipo_palet', ''))
            set_col('kilos',      prod['kilos'])
            set_col('bul_plt',    prod['bul_plt'])
            set_col('palets',     prod['palets'])
            set_col('bultos',     prod['bultos'])
            set_col('precio',     prod['precio'])
            set_col('procesado',  fecha_proc)

            service.spreadsheets().values().append(
                spreadsheetId=SHEET_ID, range="Pedidos!A:A",
                valueInputOption="RAW", insertDataOption="INSERT_ROWS",
                body={"values": [nueva_fila]}
            ).execute()
            insertadas += 1

        return jsonify({
            "ok": True, "pedido": datos['pedido'], "cliente": datos['cliente'],
            "fecha_salida": datos['fecha_salida'], "productos": len(datos['productos']),
            "insertadas": insertadas, "omitidas": omitidas, "metodo": "parser_directo"
        })

    except Exception as e:
        import traceback
        return jsonify({"ok": False, "error": str(e), "trace": traceback.format_exc()[-500:]})



@app.route("/api/importar-csv", methods=["POST"])
def importar_csv():
    """
    Importa CSV de pedidos desde el programa de gestión.
    Columnas esperadas (con espacios extra): 
      Fecha Salida, Pedido, Cliente, Destino, Referencia, Producto,
      Categoria (I/II), Tipo Palet, Lote, Palets, Bultos, Kilos, Precio
    Reemplaza TODOS los pedidos de la hoja (borrar + reescribir).
    """
    try:
        if 'file' not in request.files:
            return jsonify({"ok": False, "error": "No se recibió archivo"})

        f = request.files['file']
        if not f.filename.lower().endswith('.csv'):
            return jsonify({"ok": False, "error": "El archivo debe ser CSV"})

        import io as _io2
        import csv

        raw = f.read().decode('utf-8', errors='replace')
        reader = csv.DictReader(_io2.StringIO(raw))

        # Normalizar nombres de columna (quitar espacios extra)
        raw_headers = reader.fieldnames or []
        col_map = {h: h.strip() for h in raw_headers}

        fecha_proc = now_madrid().strftime('%d/%m/%Y %H:%M')

        # Cabecera de la hoja Pedidos (orden fijo)
        HEADER = [
            "Pedido", "Tipo", "Cliente", "Destino", "Referencia",
            "Fecha Pedido", "Fecha Salida", "Fecha Llegada",
            "Producto", "T.Cult", "Lote", "C/C", "Envase", "Tipo Palet",
            "Kilos", "Bul/Plt", "Palets", "Bultos", "Precio",
            "Matricula", "Transportista", "Total Palets", "Total Bultos",
            "Total Importe", "Observaciones", "Fecha Procesado"
        ]

        def get(row, *keys):
            for k in keys:
                for orig, clean in col_map.items():
                    if clean.lower() == k.lower():
                        v = row.get(orig, '').strip()
                        if v: return v
            return ''

        rows_nuevas = [HEADER]
        n = 0
        for row in reader:
            pedido   = get(row, 'pedido')
            if not pedido: continue

            cliente  = get(row, 'cliente')
            destino  = get(row, 'destino')
            ref      = get(row, 'referencia')
            producto = get(row, 'producto')
            cat      = get(row, 'categoria')   # I / II → T.Cult / C/C
            tipo_pal = get(row, 'tipo palet')
            lote     = get(row, 'lote')
            palets   = get(row, 'palets pro', 'palets')  # Palets Pro = palets confirmados
            bultos   = get(row, 'bultos')
            kilos    = get(row, 'kilos')
            precio   = get(row, 'precio')
            fecha_sal= get(row, 'fecha salida')

            # Categoria: I → ECO / BIO, II → CONV — se guarda en T.Cult
            t_cult = 'ECO' if cat.strip().startswith('I') and not cat.strip().startswith('II') else 'CONV'

            rows_nuevas.append([
                pedido, 'PEDIDO', cliente, destino, ref,
                '',          # Fecha Pedido (no viene en CSV)
                fecha_sal,   # Fecha Salida
                '',          # Fecha Llegada
                producto, t_cult, lote, '', '',  # C/C y Envase vacíos (no están en CSV)
                tipo_pal,
                kilos, '',   # Bul/Plt vacío
                palets, bultos, precio,
                '', '',      # Matricula, Transportista
                '', '', '',  # Total Palets, Total Bultos, Total Importe
                '',          # Observaciones
                fecha_proc
            ])
            n += 1

        # Borrar hoja Pedidos y reescribir
        service = get_sheets_service()

        # 1. Borrar todo el contenido actual de la hoja Pedidos
        service.spreadsheets().values().clear(
            spreadsheetId=SHEET_ID,
            range="Pedidos!A:Z"
        ).execute()

        # 2. Escribir todos los datos de una vez
        service.spreadsheets().values().update(
            spreadsheetId=SHEET_ID,
            range="Pedidos!A1",
            valueInputOption="RAW",
            body={"values": rows_nuevas}
        ).execute()

        return jsonify({
            "ok": True,
            "importados": n,
            "fecha": fecha_proc,
            "mensaje": f"{n} pedidos importados correctamente"
        })

    except Exception as e:
        import traceback
        return jsonify({"ok": False, "error": str(e), "trace": traceback.format_exc()[-600:]})


@app.route("/api/alertas-webhook", methods=["POST"])
def alertas_webhook():
    """Recibe alertas desde Apps Script y las guarda en Google Sheets (hoja Alertas)."""
    try:
        data = request.get_json()
        nuevas = data.get("alertas", [])
        if not nuevas:
            return jsonify({"ok": True, "msg": "sin alertas"})

        service = get_sheets_service()

        # Crear hoja Alertas si no existe
        spreadsheet = service.spreadsheets().get(spreadsheetId=SHEET_ID).execute()
        sheet_names = [s["properties"]["title"] for s in spreadsheet["sheets"]]
        if "Alertas" not in sheet_names:
            service.spreadsheets().batchUpdate(
                spreadsheetId=SHEET_ID,
                body={"requests": [{"addSheet": {"properties": {"title": "Alertas"}}}]}
            ).execute()
            service.spreadsheets().values().update(
                spreadsheetId=SHEET_ID, range="Alertas!A1",
                valueInputOption="RAW",
                body={"values": [["Fecha", "MsgID", "Tipo", "Pedido", "Asunto", "Remitente", "Leida"]]}
            ).execute()

        rows = []
        for a in nuevas:
            rows.append([
                a.get("fecha", ""), a.get("id", ""), a.get("tipo", ""),
                a.get("num", ""), a.get("asunto", ""), a.get("remitente", ""), "NO"
            ])

        service.spreadsheets().values().append(
            spreadsheetId=SHEET_ID, range="Alertas!A:A",
            valueInputOption="RAW", insertDataOption="INSERT_ROWS",
            body={"values": rows}
        ).execute()

        return jsonify({"ok": True, "guardadas": len(rows)})
    except Exception as e:
        return jsonify({"ok": False, "error": str(e)})


@app.route("/api/alertas")
def alertas():
    """Devuelve las alertas guardadas en la hoja Alertas."""
    try:
        service = get_sheets_service()
        result = service.spreadsheets().values().get(
            spreadsheetId=SHEET_ID, range="Alertas!A:G"
        ).execute()
        rows = result.get("values", [])
        if len(rows) < 2:
            return jsonify({"ok": True, "alertas": []})

        headers = [h.lower() for h in rows[0]]
        def col(name):
            try: return headers.index(name)
            except: return -1

        alertas_list = []
        for row in reversed(rows[1:]):  # Más recientes primero
            def get(n):
                i = col(n)
                return row[i].strip() if i >= 0 and i < len(row) else ""
            alertas_list.append({
                "fecha":     get("fecha"),
                "id":        get("msgid"),
                "tipo":      get("tipo"),
                "num":       get("pedido"),
                "pedido":    "Pedido " + get("pedido") if get("pedido") else "Ver email",
                "asunto":    get("asunto"),
                "remitente": get("remitente"),
                "leida":     get("leida").upper() == "SI"
            })

        return jsonify({"ok": True, "alertas": alertas_list[:50]})
    except Exception as e:
        return jsonify({"ok": True, "alertas": [], "error": str(e)})


